function toTitle(str) {
  return (str || "")
    .toLowerCase()
    .trim()
    .replace(/\b\w/g, c => c.toUpperCase());
}

function normalizeDate(dateStr) {
  if (!dateStr) return "";

  const today = new Date();

  if (dateStr.toLowerCase() === "today") {
    return today.toISOString().split("T")[0];
  }

  if (dateStr.toLowerCase() === "yesterday") {
    const y = new Date(today);
    y.setDate(today.getDate() - 1);
    return y.toISOString().split("T")[0];
  }

  return dateStr;
}

const data = $input.all()[0].json.message?.content || $input.all()[0].json;

const expenses = data.expenses || [data];

let rows = [];

for (const exp of expenses) {
  for (const item of exp.items || []) {
    rows.push({
      json: {
        source: exp.source,
        date: normalizeDate(exp.date),
        vendor: toTitle(exp.vendor),
        item: toTitle(item.name),
        category: toTitle(item.category),
        quantity: item.quantity,
        price: item.price
      }
    });
  }
}

return rows;

const staticData = $getWorkflowStaticData('global');
const items = $input.all().map(item => item.json);

if (items.length === 0 || !items[0].item) {
  return [];
}

staticData.pendingExpense = JSON.parse(JSON.stringify(items));

let msg = '📊 Below are the confirmed expenses\n\n';
msg += '📅 Date: ' + (items[0].date || 'N/A') + '\n';
msg += '🏪 Vendor: ' + (items[0].vendor || 'N/A') + '\n\n';
msg += '📝 Items:\n';

for (const item of items) {
  msg += '  • ' + (item.item || 'Unknown');
  msg += ' | ' + (item.category || '');
  msg += ' | Qty: ' + (item.quantity || '-');
  msg += ' | ₹' + (item.price || '0') + '\n';
}

const total = items.reduce((sum, i) => sum + (parseFloat(i.price) || 0), 0);
msg += '\n💰 Total: ₹' + total.toFixed(2);
msg += '\n\n👇 Select payment method:';

const apiBody = {
  chat_id: 'YOUR_CHAT_ID',
  text: msg,
  reply_markup: {
    inline_keyboard: [
      [
        { text: '💳 Credit Card', callback_data: 'pm_credit_card' },
        { text: '💳 Debit Card', callback_data: 'pm_debit_card' }
      ],
      [
        { text: '📱 UPI', callback_data: 'pm_upi' },
        { text: '🏦 Account Transfer', callback_data: 'pm_bank_transfer' }
      ],
      [
        { text: '💵 Cash', callback_data: 'pm_cash' },
        { text: '🎁 Gift Card', callback_data: 'pm_gift_card' }
      ]
    ]
  }
};

return [{ json: { apiBody } }];

function getSheetName(dateStr) {
  const months = ['JAN','FEB','MAR','APR','MAY','JUN','JUL','AUG','SEP','OCT','NOV','DEC'];
  if (!dateStr) return months[new Date().getMonth()];

  const monthNames = { jan:0, feb:1, mar:2, apr:3, may:4, jun:5, jul:6, aug:7, sep:8, oct:9, nov:10, dec:11 };
  const nameMatch = dateStr.match(/\b(jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec)\b/i);
  if (nameMatch) return months[monthNames[nameMatch[1].toLowerCase()]];

  const isoMatch = dateStr.match(/^\d{4}-(\d{2})-\d{2}$/);
  if (isoMatch) return months[parseInt(isoMatch[1]) - 1];

  const d = new Date(dateStr);
  if (!isNaN(d.getTime())) return months[d.getMonth()];

  return months[new Date().getMonth()];
}

const staticData = $getWorkflowStaticData('global');
const callback = $input.all()[0].json.callback_query;
const callbackData = callback.data;
const chatId = String(callback.message.chat.id);

const paymentModes = {
  'pm_credit_card': 'Credit Card',
  'pm_debit_card': 'Debit Card',
  'pm_upi': 'UPI',
  'pm_bank_transfer': 'Account Transfer',
  'pm_cash': 'Cash',
  'pm_gift_card': 'Gift Card'
};

const paymentMode = paymentModes[callbackData] || callbackData.replace('pm_', '').replace(/_/g, ' ');
const items = staticData.pendingExpense || [];

delete staticData.pendingExpense;

if (items.length === 0) {
  return [{
    json: {
      noData: true,
      chatId: chatId,
      paymentMode: paymentMode
    }
  }];
}

const sheetName = getSheetName(items[0].date);

return items.map(item => ({
  json: {
    ...item,
    paymentMode: paymentMode,
    chatId: chatId,
    sheetName: sheetName
  }
}));

