(() => {
  const data = $json.message?.content || $json.content;

  if (!data) {
    return "No data found.";
  }

  let itemsText = "";

  if (data.items && data.items.length > 0) {
    itemsText = data.items.map(i =>
      "- " + (i.name || "") + " | " +
      (i.category || "") + " | " +
      (i.quantity || "") + " | " +
      (i.price || "")
    ).join("\n");
  } else {
    itemsText = "- General Expense | Other |  | " + (data.total_amount || "");
  }

  const codeBlock = "```\n" +
    "vendor: " + (data.vendor || "") + "\n" +
    "date: " + (data.date || "") + "\n\n" +
    itemsText +
    "\n```";

  const total = data.total_amount || "N/A";

  return codeBlock + 
    "\n\nTotal: ₹" + total + 
    "\n*📊 Parsed Expense*";
})()
}}
